var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"크하핫! 이래가지고 날 죽일 수야 있겠어?","JPN":"くははっ！　そんなんでアタシを殺せるのか？","ENG":"Kahaha! You think that's enough to kill me?","TWN":"哈哈哈！這樣能把我殺了嗎？"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"나한테 이건 싸움 축에도 못 낀다고…!","JPN":"こんなの戦いのうちにも入らないぞ……！","ENG":"This doesn't even count as a fight to me...!","TWN":"對我來說這根本稱不上是戰鬥…！"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"유감이지만 군율 상 싸움은 금지되어 있거든.","JPN":"残念だが、軍の規律上喧嘩は禁止されていてね。","ENG":"Sorry, but per regulations, fighting's prohibited.","TWN":"雖然很遺憾，但軍規上禁止打鬥。"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"단둘이서 하는 데이트는… 다음으로 미루자고!","JPN":"2人きりのデートは……また今度な！","ENG":"Let's postpone our one-on-one date... till later!","TWN":"兩個人單獨約會…就推遲到下次吧！"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"라이트닝──! 익스큐션──!!","JPN":"ライトニング───！　エクスキューージョン！！","ENG":"Lightning──! Execution──!!","TWN":"雷光──！處刑──！！"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"저 아가씨가 상층에서 내려왔다면 승강기를 쓸 수 있다는 소리겠지.","JPN":"あのお嬢ちゃんが上層から降りてきたってことは、昇降機は使えるようになってるな。","ENG":"If that girl came down from the upper level, the elevator must be usable.","TWN":"要是那個小姐從上層下來的話，就代表能用電梯了吧。"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"본부 쪽 움직임이 없었던 걸 보면 승강기에 문제가 있을 순 있지만, 다이브 부하야 견디면 그만이야.","JPN":"本部側の動きがなかったからまだ問題があるかもしれないが、ダイブの負荷は耐えればいい。","ENG":"HQ hasn't moved, so the elevator might be janky, but I can tank the dive load.","TWN":"看本部那邊毫無動靜，可能是電梯有問題，但只要撐過躍入負荷就好。"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"서두르지 않으면 카일과 실비아가…….","JPN":"急がないとカイルとシルビアが……","ENG":"If I don't hurry, Kyle and Sylvia will...","TWN":"要是不快一點，凱爾和希爾維亞……"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"……이런.","JPN":"……おっと。","ENG":"...Well, great.","TWN":"……天哪，"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"이정도로 야성미 넘치는 레이디인 줄 몰랐는데.","JPN":"ここまでワイルドなレディーとは思わなかったが。","ENG":"Didn't know you were such a wild one.","TWN":"沒想到妳是這麼充滿野性的小姐。"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"방금 공격은 제법이었다.","JPN":"さっきの攻撃はなかなかのものだった。","ENG":"That last strike wasn't that bad.","TWN":"剛才的攻擊很不錯。"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"이 정도면…… 싸움이라고 부를 수준은 되겠어.","JPN":"これで……戦いといえるレベルにはなったな。","ENG":"At this level... I'll call it a real fight.","TWN":"這樣的話……水準應該能稱得上是戰鬥。"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"오래간만에 흥이 올랐어.","JPN":"久々に燃えてきた。","ENG":"Been a while since I felt this fired up.","TWN":"好久沒這麼有興致了。"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"네가 가진 능력으로, 날 더 재미있게 해보라고.","JPN":"あんたの能力で、もっとアタシを楽しませろ。","ENG":"Make it fun for me with everything you've got.","TWN":"用你擁有的能力，試著讓我更愉快吧。"},"stage":{"bg":"FLOOR_FACILITY_03","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"……여, 여기도 없죠?","JPN":"……こ、ここもいませんよね？","ENG":"...N-no one here either, right?","TWN":"……這、這裡也沒有吧？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"걱정 말게, 친구. 여기라면 침식체들이 눈치채지 못할 거야.","JPN":"心配するな、友よ。ここなら侵食体に気づかれずに済む。","ENG":"Don't fret, my friend. The C.O.s won't notice us here.","TWN":"別擔心，朋友，跑來這裡，侵蝕體不會發現的。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"피난민들이 남아있냐는 소리예요! 아까부터 웅크려 있지만 말고 제대로 살피라고요!","JPN":"残ってる避難民はいないかってことですよ！　うずくまってないで、ちゃんと見てください！","ENG":"I mean are there evacuees left?! Stop crouching and actually look!","TWN":"我的意思是還有難民嗎！不要從剛才開始就縮在那裡，要仔細觀察！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"훗훗. 무릇 호걸이라면 장소를 살피지 않고 안정을 취하는 법이지.","JPN":"ふふっ。豪傑は場所を問わず休憩を取るもの。","ENG":"Hmph. A true hero rests first and surveys later.","TWN":"呵呵，好漢通常不會觀察地點，而是會保持冷靜。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"이건 절대… 다, 다리가 풀린 게 아니라구.","JPN":"決して……ひ、膝が笑ってるわけではないぞ。","ENG":"And this is definitely not... b-because my legs are giving out.","TWN":"這絕對…不、不是雙腿無力。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"일 년에 한 번 올까 말까 한 호의호식이 어쩌다 공포게임으로 변질된 걸까요…….","JPN":"1年に1回来るか来ないかという豪遊のチャンスが、どうしてホラゲーに変わってしまったんでしょう……","ENG":"How did a once-in-a-year luxury trip turn into a horror game...?","TWN":"一年難得一見的好康，怎麼會變質成恐怖遊戲呢……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"컨티뉴 버튼… 되돌아갈 수 있는 세이브 데이터가 필요해요…….","JPN":"コンティニューボタン……過去に戻れるセーブデータがほしいです……","ENG":"I need a Continue button... A save file to roll back to...","TWN":"繼續鍵…需要能恢復的保存數據……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"민서, 쉿!","JPN":"ヒミコさん、しーっ！","ENG":"Minseo, shh!","TWN":"旼序，噓！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아아… 침식체가 벌써 여기까지 쫓아오다니…….","JPN":"ああ……もう侵食体がここまで追ってきた……","ENG":"Ah... The C.O.s already chased us here...","TWN":"啊啊…侵蝕體居然已經追來這裡……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"다, 다리에 쥐가 나지만 않았어도 내가 나설 텐데, 이것 참 아쉽군.","JPN":"あ、脚がしびれてなければ私が前に出たいところだが、悔しいな。","ENG":"I-I'd step up if not for this leg cramp. What a shame.","TWN":"要、要是腿沒抽筋，我就會出手，真可惜。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"……아뇨.","JPN":"……いいえ。","ENG":"...No.","TWN":"……不，"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저 침식체는 제가 어떻게든 따돌릴 테니, 두 분은 여기 조용히 숨어 계세요.","JPN":"あの侵食体は秋がなんとか撒いてみますから、2人はここで静かに隠れていてください。","ENG":"I'll draw it off somehow. You two stay hidden and quiet.","TWN":"我會想辦法甩掉那個侵蝕體，兩位就先安靜地躲在這裡吧。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아키 혼자서 뭘 어쩌게요…?","JPN":"秋さん1人でどうするつもりですか……？","ENG":"Aki, what can you even do by yourself...?","TWN":"廣瀨秋一個人要幹嘛…？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"여기서 제가 제일 빠르잖아요. 다같이 죽는 것보단 뭐라도 해보는 게 낫겠죠.","JPN":"この中じゃ秋が一番速いじゃないですか。全滅するよりは、何かしらやってみたほうがいいでしょう。","ENG":"I'm the fastest here. Better to try something than die together.","TWN":"這裡我動作最快，比起大家一起死，至少做些什麼會比較好吧。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"으으…….","JPN":"うう……","ENG":"Ugh...","TWN":"呃呃……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그럼 하다못해… 아키 양을 위해 저희만의 의식을 치르죠.","JPN":"じゃあ、せめて……ヒミコたちは秋さんのための儀式を行います。","ENG":"Then at least... let's hold a little rite for Aki.","TWN":"那實在沒辦法了…就為廣瀨秋小姐舉行專屬我們的儀式吧。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"L23_1","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};